def mergeKLists(lists):
    import heapq
    dummy = ListNode(0)
    curr = dummy
    h = []
    for i, l in enumerate(lists):
        if l:
            heapq.heappush(h, (l.val, i, l))
    while h:
        val, i, node = heapq.heappop(h)
        curr.next = ListNode(val)
        curr = curr.next
        node = node.next
        if node:
            heapq.heappush(h, (node.val, i, node))
    return dummy.next

